// Canonical allOf() helper — n8n auto-splits multi-row PostgREST
// responses; this collapses them back to a single array.
const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    return items;
  } catch (e) { return []; }
};

const rows = allOf('Close Expired Auctions');
const sold   = rows.filter(function (r) { return r.new_status === 'closed_sold'; });
const unsold = rows.filter(function (r) { return r.new_status === 'closed_unsold'; });
const totalCents = sold.reduce(function (s, r) { return s + (r.winning_amount_cents || 0); }, 0);

return { json: {
  ok: true,
  ts: new Date().toISOString(),
  processed_count:  rows.length,
  sold_count:       sold.length,
  unsold_count:     unsold.length,
  total_won_cents:  totalCents,
  results:          rows
} };
